using UnityEngine;\nusing TMPro;\n\npublic class HUDManager : MonoBehaviour\n{\n    [SerializeField] private TextMeshProUGUI altitudeText;\n    [SerializeField] private TextMeshProUGUI airspeedText;\n    [SerializeField] private TextMeshProUGUI headingText;\n    [SerializeField] private TextMeshProUGUI healthText;\n    [SerializeField] private TextMeshProUGUI ammoText;\n    [SerializeField] private TextMeshProUGUI missilesText;\n    [SerializeField] private TextMeshProUGUI scoreText;\n    [SerializeField] private CanvasGroup gameOverPanel;\n    [SerializeField] private TextMeshProUGUI gameOverText;\n\n    private PlayerAircraft playerAircraft;\n\n    private void Start()\n    {\n        playerAircraft = FindObjectOfType<PlayerAircraft>();\n    }\n\n    private void Update()\n    {\n        if (playerAircraft == null) return;\n\n        UpdateFlightData();\n        UpdateWeaponData();\n    }\n\n    private void UpdateFlightData()\n    {\n        if (altitudeText != null)\n            altitudeText.text = $\"ALT: {playerAircraft.Altitude:F0}M\";\n        if (airspeedText != null)\n            airspeedText.text = $\"SPD: {playerAircraft.Airspeed}KT\";\n        if (headingText != null)\n            headingText.text = $\"HDG: {playerAircraft.Heading:D3}\";\n        if (healthText != null)\n            healthText.text = $\"HEALTH: {(playerAircraft.Health / playerAircraft.MaxHealth * 100):F0}%\";\n    }\n\n    private void UpdateWeaponData()\n    {\n        if (ammoText != null)\n            ammoText.text = $\"AMMO: {playerAircraft.Ammo}\";\n        if (missilesText != null)\n            missilesText.text = $\"MISSILES: {playerAircraft.Missiles}\";\n        if (scoreText != null)\n            scoreText.text = $\"SCORE: {playerAircraft.Score}\";\n    }\n\n    public void ShowGameOver(string reason)\n    {\n        if (gameOverPanel != null)\n            gameOverPanel.alpha = 1f;\n        if (gameOverText != null)\n            gameOverText.text = reason;\n    }\n}\n"